solutions.cpp:
class Solution {
public:
    bool TriePrefixSearch(vector<vector<int>>& trie, string query) {
        for (auto node : trie) {
            if (node[0] == query[0] && node[1] != -1) {
                return true;
            }
        }
        return false;
    }
};
int main() {
    vector<vector<int>> trie = {{1, 2, 3}, {4, 5, 6}, {-1, -1, -1}};
    string query = "1";
    Solution solution;
    cout << (solution.TriePrefixSearch(trie, query) ? "True" : "False") << endl;
    return 0;
}
